CREATE TABLE transactions (
  txn_id       SERIAL PRIMARY KEY,
  account_id   INT,
  txn_date     DATE,
  amount       DECIMAL(10,2),
  txn_type     VARCHAR(20),
  description  VARCHAR(200)
);

INSERT INTO transactions (account_id, txn_date, amount, txn_type, description)
SELECT
  (random() * 1000 + 1)::INT,
  '2025-01-01'::DATE + (random() * 365)::INT,
  (random() * 10000)::DECIMAL(10,2),
  CASE WHEN random() < 0.5 THEN 'credit' ELSE 'debit' END,
  'Transaction description ' || generate_series
FROM generate_series(1, 1000);

-- Without index: query must scan all 1000 rows
EXPLAIN SELECT * FROM transactions WHERE account_id = 42;

-- Create B-tree index on account_id
CREATE INDEX idx_txn_account ON transactions(account_id);

-- With index: should show Index Scan or Bitmap Index Scan
EXPLAIN SELECT * FROM transactions WHERE account_id = 42;

-- Range query with date index
CREATE INDEX idx_txn_date ON transactions(txn_date);
EXPLAIN SELECT * FROM transactions WHERE txn_date BETWEEN '2025-06-01' AND '2025-08-31';
